var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>캄파멘토</color>\\n어두운 숲 지대 <color=#ffd34c>CSE</color> LV. 3","JPN":"管理局直轄都市<color=#ffd34c>カンパメント</color>\\n暗い森地帯<color=#ffd34c>CSE</color> LV.3","ENG":"Administration Direct Control City, <color=#ffd34c>Campamento</color>\\nDark Forest Zone, <color=#ffd34c>CSE</color> Lv. 3","TWN":"管理局直轄市 <color=#ffd34c>坎帕門托</color>\\n黑暗森林地帶 <color=#ffd34c>CSE</color> LV. 3"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"거의 도착했어요! 베이스 캠프까지 앞으로 조금입니다!","JPN":"ほぼ到着しました！　ベースキャンプまであと少しです！","ENG":"We're almost there! Just a bit further to the base camp!","TWN":"快到了！營區就在前面而已！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L10_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"하하, 참말로. 뭐가 꼬여도 단단히 꼬였구만!","JPN":"あはは、まいった。こりゃ大変だわ！","ENG":"Haha, really. Things are seriously tangled this time!","TWN":"哈哈，真是的。真是麻煩！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"캄파멘토 베이스 캠프가 코 앞인데도, CSE 레벨이 3에서 안 내려간다고?","JPN":"カンパメントのベースキャンプが目の前にあんのに、CSEレベルがまだ3やと？","ENG":"We're right by Campamento's base camp, and the CSE level won't drop below 3?","TWN":"坎帕門托營區就在眼前，CSE等級卻不降到3以下嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"저 머리 위에 천공 대균열 때문인기가……?","JPN":"頭の上の天空大亀裂のせいか……？","ENG":"Is it because of that Grand Dimension Crevice floating above us...?","TWN":"是因為我頭上的天空大峽谷嗎……？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AURA_ADMIN_NULL_NULL","text":{"KOREA":"스파이럴!","JPN":"スパイラル！","ENG":"Spiral!","TWN":"迴旋！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AURA_ADMIN_NULL_NULL","text":{"KOREA":"하아아아아아아아앗────!!","JPN":"はあああああああああ────っ！！","ENG":"Haaaaaah────!!","TWN":"嚇啊啊啊啊啊啊啊啊————！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"미리네 씨, 이쪽은 정리가 끝났어요! 미리네 씨는……","JPN":"マリさん、こっちは片付きました！　マリさんの方は……","ENG":"Ms. Mi Rinae, it's clear over here! What about you—","TWN":"宓璃奈，這邊都解決了！你那邊……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"음!?","JPN":"え！？","ENG":"Mm?!","TWN":"嗯！？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"우오……!","JPN":"うお……！","ENG":"Whoa...!","TWN":"哇喔……！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"니 방금 침식체를 쓰러트리고 난 뒤의 마지막 그 포즈……!","JPN":"あんた、今のあの、侵食体を倒した後の決めポーズ……！","ENG":"That finishing pose you just struck after downing the C.O...!","TWN":"你最後打倒侵蝕體的那個姿勢……！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그거 혹시 가면 카운터 무인편에 나오는 마무리 포즈를 따라한 거 아아가……?","JPN":"それってもしかして仮面カウンター武人編の決めポーズちゃうん……？","ENG":"Wasn't that copied from the Masked Counter's Unmanned Arc...?","TWN":"是不是在模仿蒙面制裁者首部曲裡的Ending pose……？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"혹시 가면 카운터 좋아하나? 내는 완전 팬이다!","JPN":"仮面カウンター好きなん？　ウチめっちゃファンなんやけど！","ENG":"Are you a Masked Counter fan? I'm a huge one!","TWN":"你喜歡蒙面制裁者嗎？我是超級粉絲！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"미리네 씨도 가면 카운터를 좋아하는 군요!","JPN":"マリさんも仮面カウンターがお好きなんですね！","ENG":"So you like Masked Counter too, Ms. Mi Rinae!","TWN":"你也喜歡蒙面制裁者！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"알다마다! 가면 카운터를 좋아하는 녀석들 중에 악당은 없다카이!","JPN":"もちろんや！　仮面カウンター好きなやつに悪いやつはおらへんで！","ENG":"Of course! Anyone who likes Masked Counter can't be a villain!","TWN":"當然！喜歡蒙面制裁者的人都是好人！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"포즈의 재현도 꽤 높다 아이가! 이거 은근히 팔 각도 맞추는 게 핵심이라고?","JPN":"ポーズの再現度も高いわ！　腕の角度合わせんの地味に難しいよな！","ENG":"And you nailed the angle of that pose! Getting the arm right is the key, you know?","TWN":"姿勢的還原度還蠻高的嘛！這關鍵在於調整手臂的角度。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"와, 맞아요……!","JPN":"わあ、そうなんです……！","ENG":"Wow, you're right...!","TWN":"哇，沒錯……！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"오러 선생님께서는 항상 자신 있는 자세에서 자신감이 나온다고 하셨거든요.","JPN":"オーラ先生はいつも、自信はシャキッとした姿勢から生まれるものだとおっしゃるんです。","ENG":"Ms. Aura always said confidence comes from standing tall in your best pose.","TWN":"奧蘿師父總是說，自信源於自信的姿態。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"사실, 자신감이 조금 부족한 편이라… 매일 거울을 보고 멋진 포즈를 연습하고 있어요!","JPN":"実は私、自信が少し足りなくて……毎日鏡を見て格好いいポーズを練習しています！","ENG":"Truth is, I lack confidence... so I practice poses in the mirror every day!","TWN":"其實，我有點缺乏自信……每天都在鏡子前練習帥氣的姿勢！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그라제, 뭐든 꾸준히 하는 게 중요한기다.","JPN":"ええな！　何事もコンスタントに続けることが大事や。","ENG":"Exactly. Consistency is everything.","TWN":"沒錯，做什麼事情都要堅持不懈才行。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"소싯적에는 내도 가면 카운터 포즈 좀 연습했다 안카나.","JPN":"ウチも昔は仮面カウンターのポーズ練習してたわ。","ENG":"Back in the day, I practiced Masked Counter poses too.","TWN":"小時候我也練習過蒙面制裁者的姿勢呢。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"싸울겁니다! 저는 이 이상 누군가의 눈물을 보고 싶지 않아요!","JPN":"「戦います！　俺は、これ以上誰かの涙は見たくない！」","ENG":"Because of punks like you, I refuse to watch anyone cry again!","TWN":"我要戰鬥！我不想再看到任何人的眼淚！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_05"},{"id":"L39_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"변신, 가면 카운터 1호────","JPN":"「変身！　仮面カウンター1号────」","ENG":"Transform! Masked Counter No. 1────","TWN":"變身，蒙面制裁者1號────"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"크핫!?","JPN":"ぐはっ！？","ENG":"Oof?!","TWN":"唔！？"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_BONE_CRACK"},{"id":"L41_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"4번 디스크가 또!?","JPN":"腰椎の4番がまた！？","ENG":"My back again?!","TWN":"我的第4節脊椎又！?"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L43_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"괘, 괜찮으세요, 미리네 씨!?","JPN":"だ、大丈夫ですか、マリさん！？","ENG":"A-are you all right, Ms. Mi Rinae?!","TWN":"你，你沒事吧，宓璃奈？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"하하, 내 농담이다. 농담!","JPN":"あはは、冗談や冗談！","ENG":"Haha, just kidding!","TWN":"哈哈，我開玩笑的，開玩笑！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"하, 하하… 그래도 저랑 같은 취미가 있는 분은 처음 봐요!","JPN":"あ、あはは……でも、私と同じ趣味を持ってる方に会ったのは初めてです！","ENG":"Ha... haha... Still, it's my first time meeting someone who shares this hobby.","TWN":"哈，哈哈……不過我還是第一次見到和我有相同愛好的人呢！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"세상 참 넓고, 사람 취향은 가지가지 아이가?","JPN":"世界は広いし、人の趣味もそれぞれや。","ENG":"The world's wide and people's tastes are endless.","TWN":"世界真大，人們的喜好真是千奇百怪呢？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"흐음, 근데 가만 생각해보니 신기하네잉.","JPN":"それにしても……ふーん、不思議なもんやな。","ENG":"Hmm, but come to think of it, that's curious.","TWN":"哼，不過仔細想想還真是神奇欸。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그 가면, 니가 직접 만든 기가? 목소리 나오는 거 보니까, 보이스 기능도 있는 갑제?","JPN":"その仮面、あんたが作ったん？　声も出てるし、ボイス機能でもあんの？","ENG":"That mask. Did you make it yourself? And it seems to even have voice output?","TWN":"那個面具，是你自己做的嗎？看樣子還有語音功能呢？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"요새 나오는 가면 카운터 시리즈가? 거, 굿즈 퀄리티 하나는 기가 막히네.","JPN":"それとも最近の仮面カウンターのグッズ？　えらいクオリティーだわ。","ENG":"Is that one of the latest Masked Counter merch? The quality's insane.","TWN":"是最近出的蒙面制裁者系列嗎？哇，這周邊的品質真是厲害咧。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"아, 이건 굿즈가 아니라, 오러 선생님이에요.","JPN":"あ、これはグッズじゃなくてオーラ先生です。","ENG":"Ah, this isn't merch. This is Ms. Aura.","TWN":"呃，這不是周邊商品，是奧蘿師父。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_PRIDE"}}}},{"id":"L1_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"지금은 이렇지만 선생님께서는 구관리국 라만차 돌격 전대의 전대장이셨거든요.","JPN":"今はこんな姿ですが、先生は旧管理局ラマンチャ突撃戦隊の戦隊長だったんです。","ENG":"She may look like this now, but she was once commander of the Old Administration's La Mancha Stormtrooper Division.","TWN":"雖然現在是這樣，但老師曾是舊管理局拉曼查突擊戰隊的隊長呢。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"으음? 그 가면이 구관리국의 전대장이라고?","JPN":"え？　その仮面が旧管理局の戦隊長？","ENG":"Huh? That mask was a commander of the Old Administration?","TWN":"嗯？那個面具是舊管理局的戰隊長嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"네, 저는 오러 선생님의 종자고요.","JPN":"はい、そして私はオーラ先生の従者です。","ENG":"Yes. And I'm Ms. Aura's squire.","TWN":"是的，我是奧蘿師父的手下。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"선생님과 저는 이 세계의 정의를 실현하기 위해 전 세계를 떠돌고 있어요.","JPN":"先生と私は、正義を実現するために世界中を旅しています。","ENG":"Together we travel the world, bringing justice wherever it's needed.","TWN":"我們正在為實現這個世界的正義而遊走世界。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"저는 아직 경험이 부족하지만… 선생님과 함께라면 누구보다 강해질 수 있어요……!","JPN":"私はまだ未熟ですが……先生と一緒なら、誰よりも強くなれます……！","ENG":"I'm still inexperienced, but with her, I know I can become stronger than anyone...!","TWN":"我雖然經驗不足……但只要和老師在一起，我一定能變得比任何人都強……！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"으으음……?","JPN":"うーん……？","ENG":"Hmm...?","TWN":"呃呃嗯……？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"아하, 그런 설정이가!","JPN":"なるほど、そういう設定やな！","ENG":"A-ha, so that's the lore, huh!","TWN":"啊哈，原來是這樣的人設！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L10_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"네? 설정이요?","JPN":"え？　設定？","ENG":"Huh? Lore?","TWN":"什麼？人設？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"제법인데? 가면을 쓰면 강해지는 설정이라… 오러라고 했나? 낭만을 좀 아는기라!","JPN":"やるなあ。仮面を被ると強くなる設定か……オーラって言ったか？　ロマンがあるな！","ENG":"Not bad. A mask that makes you stronger... Aura, was it? That's some style!","TWN":"不錯嘛？戴上面具就會變強的人設……是叫奧蘿嗎？很會喔！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"아, 아니요! 이건 설정이 아니라……!","JPN":"い、いいえ！　これは設定じゃなくて……！","ENG":"N-no, it's not lore, it's real...!","TWN":"不是的！這不是人設……！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"마, 됐다. 됐어~ 관리국 선배로서 그 정도는 맞춰 줄 수 있는 기라~","JPN":"まあまあ、管理局の先輩として、そんぐらいつき合ったるで。","ENG":"Ah, whatever. As your senior in the Administration, I'll play along.","TWN":"好了，好了～作為管理局的前輩，這點小事我可以配合你～"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그리고 이런 설정은, 보통 힘을 완전히 못 다스리는 게 정석 전개 아이가?","JPN":"それにこういう設定って普通、まだ力を制御しきれないってのがお決まりやろ。","ENG":"And usually in stories like that, you can't fully control the power, right?","TWN":"而且這種人設通常都是無法完全掌控力量不是嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"네? 아아, 네……!","JPN":"え？　ああ、はい……！","ENG":"What? Ah, yes...!","TWN":"什麼？嗯嗯，對……！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"아직은 제가 수련이 부족해서, 오러 선생님과의 동조율이 높지 않거든요.","JPN":"まだ修行が足りなくて、オーラ先生との同調率がそんなに高くないんです。","ENG":"I'm still lacking in training, so my synchronization with Ms. Aura isn't very high.","TWN":"我現在修煉還不夠，所以和奧蘿師父的同步率不高。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"만일의 사태를 위해, 선생님과의 동조는 불가피한 전투 상황을 위해, 아껴두고 있어요.","JPN":"万が一、どうしても戦わないといけない状況になる可能性に備えて、先生と同調するのは控えています。","ENG":"We're saving that full sync for an emergency battle.","TWN":"以防萬一，我只在不可避免的戰鬥情況下才會和老師同步。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"으음, 역시 그런갑네…….","JPN":"ふむふむ、やっぱりか……","ENG":"Mm, makes sense...","TWN":"嗯，果然是這樣……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"관리국의 선배님으로서 역시 이 말을 안 해줄 수가 없군.","JPN":"これは管理局の先輩として、ひとこと言ってやらんとな。","ENG":"As your senior in the Administration, I can't not say this.","TWN":"作為管理局的前輩，我還是要說一句。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"오러화, 제어하고 싶제?","JPN":"オーラ化、制御したいんやろ？","ENG":"Want to control your Aurafication?","TWN":"想控制奧蘿化嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L24_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"……네? 오러화요?","JPN":"……え？　オーラ化？","ENG":"...Excuse me? \\"Aurafication\\"?","TWN":"……嗯？奧蘿化嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"크흠, 흠……!","JPN":"ご、ごほん……！","ENG":"Ahem, hem...!","TWN":"咳，咳……！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"아하하…! 역시 요즘 아들은 이런 옛날 만화 농담은 잘 모르제……?","JPN":"あはは……！　やっぱり最近の若い子は笑いのツボがちゃうか。","ENG":"Ahaha...! Guess kids these days don't know the old manga jokes.","TWN":"啊哈哈…！果然現在的年輕人不太懂這種漫畫的老梗呢……？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"아무튼 그 가면이 뭔진 몰라도 아티팩트라 카면, 거기에 맞는 쓰임새가 있을 끼다.","JPN":"とにかく、その仮面が何かは分からへんけど、アーティファクトなら適切な使い方があるで。","ENG":"Anyway, whatever that mask is, if it's an Artifact, it's got its purpose.","TWN":"總之，不管那個面具是什麼，如果是人造神器的話，那就會有相應的用途。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"싱크로율을 높일 수 있는 방법도, 분명 있을 낀데…….","JPN":"シンクロ率を高められる方法も、きっとあるはずやねんけど……","ENG":"And there's bound to be a way to boost your synch rate...","TWN":"肯定有辦法可以提高同步率……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"좋다, 나만 믿으라고, 로빈 피츠워터 양!","JPN":"よし！　ウチに任しとき、ロビン・フィッツウォーター！","ENG":"All right. Trust me, Robin Fitzwater!","TWN":"好吧，相信我，蘿蘋·菲茲瓦特！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L33_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"이번 작전에서 니 잠재력을 끌어낼 수 있게, 내가 전력으로 서포트 해줄기라!","JPN":"この作戦であんたの潜在能力を引き出せるよう、ウチが全力でサポートしたるで！","ENG":"I'll give my all in this mission to help you unleash your potential!","TWN":"在這次作戰中，我會全力支持你，幫助你發揮潛力！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};